INSERT INTO recovery_packages (deduction_id, customer_id, invoice_ref, amount, correspondence_letter, status, follow_up_cadence_count) VALUES ('7f672b12-7806-4559-9b75-e999416194d0', 'USCU_L10', '90000000', 21300.00, 'Dear Crestline Grocery AP Team,\n\nWe reject the shortage deduction of $21,300 on invoice 90000000. Our 3PL proof of delivery shows the shipment of 1,200 cases was received in full, signed by Crestline Receiver on 2026-06-14 with no exceptions.\n\nPlease find the signed POD attached.\n\nSincerely,\nNorthBay Brands Claims Department', 'GENERATED', 1);
INSERT INTO recovery_packages (deduction_id, customer_id, invoice_ref, amount, correspondence_letter, status, follow_up_cadence_count) VALUES ('bf297e9b-d67e-4a3c-b608-e622c5b871fe', 'USCU_S07', '90000001', 12700.00, 'Dear ValuMart Club Claims Desk,\n\nWe dispute the OTIF fine of $12,700 logged against invoice 90000001. The target delivery date was June 15, 2026. The actual delivery timestamp from our carrier and 3PL POD is June 14, 2026 at 10:00 AM, proving the shipment arrived 1 day early.\n\nPlease review and refund this penalty.\n\nSincerely,\nNorthBay Brands Claims Department', 'GENERATED', 0);
INSERT INTO recovery_packages (deduction_id, customer_id, invoice_ref, amount, correspondence_letter, status, follow_up_cadence_count) VALUES ('eabb96cc-bb46-438b-b88e-ce749865eca5', 'USCU_L10', '90000061', 18400.00, 'Dear Crestline Grocery AP Team,\n\nWe reject the pricing chargeback of $18,400 on invoice 90000061. The billed unit price of $15.00 matches the pricing terms defined in contract CON_CREST_01. The deduction has no contractual basis.\n\nSincerely,\nNorthBay Brands Claims Department', 'GENERATED', 0);
